<template>
    <div class="main-header">
        <img :src="store.state.userInfo.avatar" class="avatar" @click="editPersonal()" />
        <div class="nickName">{{ store.state.userInfo.nickname }}</div>
        <div class="rest"></div>
        <div class="menu-btn" :class="{ active: store.state.activeMenu == '/home' }" @click="goMenu('/home')">
            <HomeOutlined class="menu-icon" />
            <div class="text">首页</div>
        </div>
        <div class="menu-btn" :class="{ active: store.state.activeMenu == '/note' }" @click="goMenu('/note')">
            <ProfileOutlined class="menu-icon" />
            <div class="text">笔记</div>
        </div>
        <div class="menu-btn" :class="{ active: store.state.activeMenu == '/demo' }" @click="goMenu('/demo')">
            <AppstoreOutlined class="menu-icon" />
            <div class="text">样例</div>
        </div>
        <a-button type="primary" shape="round" style="margin-left:16px" @click="sendMail()">
            发送邮件
        </a-button>
        <a-button type="primary" shape="round" style="margin-left:16px" @click="editNote()">
            记笔记
        </a-button>
    </div>
</template>
<script>
import { useStore } from "vuex";
import { useRouter } from "vue-router";
import { ref } from "vue";
import { HomeOutlined, ProfileOutlined, AppstoreOutlined } from "@ant-design/icons-vue";
export default {
    setup() {
        const store = useStore();
        const router = useRouter();

        let activeMenu = ref("home");

        const goMenu = menu => {
            router.push({ path: menu });
        };

        const sendMail = () => {
            router.push({ path: "/mail" });
        };

        const editNote = () => {
            store.commit("setCurWritingArticleId", null);
            router.push({ path: "/editor" });
        };

        const editPersonal = () => {
            router.push({ path: "/personal" });
        };

        return {
            store,
            activeMenu,
            goMenu,
            sendMail,
            editNote,
            editPersonal
        };
    },
    components: {
        HomeOutlined,
        ProfileOutlined,
        AppstoreOutlined
    }
};
</script>

<style lang="scss" scoped>
.main-header {
    position: relative;
    width: 100%;
    height: 60px;
    display: flex;
    align-items: center;
    box-shadow: 0 1px 8px 0 rgba(0, 0, 0, 0.1);
    padding: 0 16px;
    background: #fff;
    z-index: 2;

    .avatar {
        width: 40px;
        height: 40px;
        border-radius: 100%;
        cursor: pointer;
    }

    .nickName {
        font-size: 24px;
        font-weight: bolder;
        margin: 0 16px;
    }

    .rest {
        flex: 1;
    }

    .menu-btn {
        margin-left: 16px;
        cursor: pointer;
        display: flex;
        align-items: center;

        .menu-icon {
            margin-right: 5px;
        }

        &:hover,
        &.active {
            color: #3489fd;
        }
    }
}
</style>
